import {gsap} from 'gsap';
import {ScrollTrigger} from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

const getHeaderColorTrigger = () => {
  const explicitTrigger = document.querySelector('[data-header-color-trigger]');

  if (explicitTrigger) {
    return explicitTrigger;
  }

  const smoothContent = document.querySelector('[data-smooth-content]');

  return smoothContent ? smoothContent.firstElementChild : null;
};

export const initHeaderColorChange = () => {
  const header = document.querySelector('[data-color-change]');
  const triggerSection = getHeaderColorTrigger();

  if (!header || !triggerSection) {
    return;
  }

  let isTicking = false;
  let headerHeight = header.offsetHeight;

  const updateHeaderState = () => {
    const sectionTop = triggerSection.getBoundingClientRect().top;
    const isIntroCovered = sectionTop <= headerHeight;

    header.classList.toggle('header--intro-covered', isIntroCovered);
    isTicking = false;
  };

  const requestUpdate = () => {
    if (isTicking) {
      return;
    }

    isTicking = true;
    requestAnimationFrame(updateHeaderState);
  };

  const onResize = () => {
    headerHeight = header.offsetHeight;
    requestUpdate();
  };

  updateHeaderState();

  ScrollTrigger.create({
    start: 0,
    end: 'max',
    onUpdate: requestUpdate,
    onRefresh: onResize,
  });

  window.addEventListener('scroll', requestUpdate, {passive: true});
  window.addEventListener('resize', onResize);
  ScrollTrigger.addEventListener('refresh', onResize);
};
