import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { ScrollToPlugin } from 'gsap/ScrollToPlugin';

gsap.registerPlugin(ScrollTrigger, ScrollToPlugin);

export const initServiceTabsScroll = () => {
  const root = document.querySelector('[data-tabs-scroll]');
  const header = document.querySelector('[data-header]');

  if (!root) {
    return;
  }

  const controls = Array.from(root.querySelectorAll('[data-tabs="control"]'));

  if (controls.length < 2) {
    return;
  }

  // Меньше расстояние между переключениями
  const getStepHeight = () => 400;
  const getScrollDistance = () => getStepHeight() * (controls.length - 1);

  let activeIndex = controls.findIndex((control) =>
    control.classList.contains('is-active')
  );

  let isProgramClick = false;
  let isProgramScroll = false;

  if (activeIndex < 0) {
    activeIndex = 0;
  }

  const activateTab = (index) => {
    const control = controls[index];
    const parent = control?.closest('[data-tabs="parent"]');

    if (
      !control ||
      !parent ||
      index === activeIndex ||
      parent.classList.contains('no-action')
    ) {
      return;
    }

    activeIndex = index;

    isProgramClick = true;
    control.click();
    isProgramClick = false;
  };

  const scrollTrigger = ScrollTrigger.create({
    trigger: root,
    start: () => `top ${header ? header.offsetHeight : 0}px`,
    end: () => `+=${getScrollDistance()}`,
    pin: true,
    pinSpacing: true,
    scrub: 0.8,
    anticipatePin: 1.5,
    fastScrollEnd: true,
    invalidateOnRefresh: true,

    onUpdate: (self) => {
      if (isProgramScroll) {
        return;
      }

      const step = 1 / controls.length;

      const index = Math.min(
        controls.length - 1,
        Math.floor((self.progress + step * 0.45) * controls.length)
      );

      activateTab(index);
    },
  });

  root.addEventListener(
    'click',
    (evt) => {
      const control = evt.target.closest('[data-tabs="control"]');

      if (!control || !root.contains(control) || isProgramClick) {
        return;
      }

      evt.preventDefault();
      evt.stopPropagation();

      const index = controls.indexOf(control);

      if (index < 0 || index === activeIndex) {
        return;
      }

      isProgramScroll = true;

      activateTab(index);

      const scrollTarget =
        scrollTrigger.start + getStepHeight() * index;

      gsap.to(window, {
        scrollTo: scrollTarget,
        duration: 0.9,
        ease: 'power3.inOut',
        overwrite: true,
        onComplete: () => {
          isProgramScroll = false;
        },
        onInterrupt: () => {
          isProgramScroll = false;
        },
      });
    },
    true
  );

  ScrollTrigger.refresh();
};