export const initStackSlider = () => {
  const swipers = document.querySelectorAll('[data-swiper]');
  if (!swipers.length) {
    return;
  }
  const mediaQuery = window.matchMedia('(max-width: 768px)');
  swipers.forEach((swiper) => {
    let slider = null;
    const enableSwiper = () => {
      if (slider) {
        return;
      }
      slider = new Swiper(swiper, {
        spaceBetween: 20,
        slidesPerView: 2.1,
        breakpoints: {
          576: {
            slidesPerView: 3.1,
          },
        },
      });
    };
    const destroySwiper = () => {
      if (slider) {
        slider.destroy(true, true);
        slider = null;
      }
    };
    const checkMedia = () => {
      if (mediaQuery.matches) {
        enableSwiper();
      } else {
        destroySwiper();
      }
    };
    checkMedia();
    mediaQuery.addEventListener('change', checkMedia);
  });
};
