import {Autoplay} from 'swiper/modules';
export const initCustomersSlider = () => {
  const swiper = document.querySelector('[data-customers-slider]');
  if (!swiper) {
    return;
  }
  const slider = new Swiper(swiper, {
    modules: [Autoplay],
    loop: true,
    slidesPerView: 2,
    spaceBetween: 70,
    speed: 5000,
    autoplay: {
      delay: 0,
      disableOnInteraction: false,
    },
    breakpoints: {
      768: {
        slidesPerView: 2.5,
      },
      1024: {
        slidesPerView: 3.5,
      },
      1160: {
        slidesPerView: 4,
      },
      1440: {
        slidesPerView: 4.5,
      },
      1600: {
        slidesPerView: 5,
      },
    },
  });
};
