import {gsap} from 'gsap';
import {ScrollTrigger} from 'gsap/ScrollTrigger';
import {ScrollSmoother} from 'gsap/ScrollSmoother';

gsap.registerPlugin(ScrollTrigger, ScrollSmoother);

const getIntroOverflow = (intro) => Math.max(0, intro.offsetHeight - window.innerHeight);

const getScrollPosition = () => ScrollSmoother.get()?.scrollTop() ?? window.scrollY;

const updateIntroTallState = (intro) => {
  intro.classList.toggle('intro-main--tall', getIntroOverflow(intro) > 0);
};

export const initIntroFix = () => {
  const intro = document.querySelector('[data-intro]');
  const flow = document.querySelector('[data-page-flow]');
  const introWrapper = intro?.querySelector('.intro-main__wrapper');

  if (!intro || !flow || !introWrapper) {
    return;
  }

  const media = gsap.matchMedia();

  media.add('(min-width: 1160px)', () => {
    const syncIntroScroll = () => {
      updateIntroTallState(intro);

      const overflow = getIntroOverflow(intro);

      if (overflow <= 0) {
        gsap.set(introWrapper, {y: 0});
        return;
      }

      const progress = Math.min(1, Math.max(0, getScrollPosition() / overflow));
      gsap.set(introWrapper, {y: -progress * overflow});
    };

    const introFixTrigger = ScrollTrigger.create({
      trigger: intro,
      start: 'top top',
      endTrigger: flow,
      end: 'bottom top',
      pin: intro,
      pinSpacing: false,
      anticipatePin: 1,
      invalidateOnRefresh: true,
      onEnter: () => intro.classList.add('is-pinned'),
      onLeaveBack: () => intro.classList.remove('is-pinned'),
    });

    const introScrollTrigger = ScrollTrigger.create({
      start: 0,
      end: 'max',
      onUpdate: syncIntroScroll,
      invalidateOnRefresh: true,
    });

    syncIntroScroll();
    ScrollTrigger.refresh();

    return () => {
      introFixTrigger.kill();
      introScrollTrigger.kill();
      gsap.set(introWrapper, {clearProps: 'transform'});
      intro.classList.remove('is-pinned', 'intro-main--tall');
    };
  });
};
