import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

const intro = document.querySelector('[data-intro]');

const getIntroAnimation = () => {
  gsap.registerPlugin(ScrollTrigger);

  const ctx = gsap.context(() => {
    const images = {
      first: intro.querySelector('[data-intro-image-first]'),
      second: intro.querySelector('[data-intro-image-second]'),
      third: intro.querySelector('[data-intro-image-third]'),
      fourth: intro.querySelector('[data-intro-image-fourth]'),
    };

    gsap.to(images.first, { y: 0, duration: 2, ease: 'sine.out' });
    gsap.to(images.second, { y: 0, duration: 2, ease: 'sine.out' });
    gsap.to(images.third, { x: 0, y: 0, z: 0, duration: 2, ease: 'sine.out' });
    gsap.to(images.fourth, { y: 0, duration: 2, opacity: 1, ease: 'sine.out' });

    const addHover = (element, config) => {
      const { scale = 1.05, rotate = 0, y = 0, duration = 0.5 } = config;

      let anim = null;

      const onEnter = () => {
        if (anim) anim.kill();
        anim = gsap.to(element, {
          scale,
          rotate,
          y,
          duration,
          ease: 'back.out(1.7)',
          overwrite: true,
        });
      };

      const onLeave = () => {
        if (anim) anim.kill();
        anim = gsap.to(element, {
          scale: 1,
          rotate: 0,
          y: 0,
          duration: duration * 0.5,
          ease: 'power2.out',
          overwrite: true,
        });
      };

      element.addEventListener('mouseenter', onEnter);
      element.addEventListener('mouseleave', onLeave);

      return () => {
        element.removeEventListener('mouseenter', onEnter);
        element.removeEventListener('mouseleave', onLeave);
        if (anim) anim.kill();
      };
    };

    addHover(images.first, { scale: 1.05, rotate: 2, duration: 0.7 });
    addHover(images.second, { scale: 1.08, rotate: -3, duration: 0.7 });
    addHover(images.third, { scale: 1.05, y: -10, duration: 0.7 });
  });

  return ctx;
};

const initIntroAnimation = () => {
  if (!intro) return;
  
  const ctx = getIntroAnimation();

  return () => {
    if (ctx) ctx.revert();
  };
};

export { initIntroAnimation };