export const initScrollButtons = () => {
  function initScrollDown() {
    const scrollDownBtn = document.querySelector('[data-scroll="down"]');
    const target = document.querySelector('[data-scroll-target="about"]');
    if (!scrollDownBtn || !target) {
      return;
    }
    scrollDownBtn.addEventListener('click', () => {
      target.scrollIntoView({
        behavior: 'smooth',
      });
    });
  }
  function initScrollUp() {
    const scrollUpBtn = document.querySelector('[data-scroll="up"]');
    if (!scrollUpBtn) {
      return;
    }
    scrollUpBtn.addEventListener('click', () => {
      window.scrollTo({
        top: 0,
        behavior: 'smooth',
      });
    });
  }
  initScrollDown();
  initScrollUp();
};
