import {gsap} from 'gsap';
import {ScrollTrigger} from 'gsap/ScrollTrigger';
import {ScrollSmoother} from 'gsap/ScrollSmoother';

gsap.registerPlugin(ScrollTrigger, ScrollSmoother);

export const initScrollSmoother = () => {
  const wrapper = document.querySelector('[data-smooth-wrapper]');
  const content = document.querySelector('[data-smooth-content]');

  if (!wrapper || !content) {
    return;
  }

  ScrollSmoother.create({
    wrapper,
    content,
    smooth: 1.1,
    effects: false,
    smoothTouch: false,
  });

  const stickyContainer = document.querySelector('[data-sticky-container]');
  const stickyItem = document.querySelector('[data-sticky-item]');

  ScrollTrigger.create({
    trigger: stickyContainer,
    start: 'top top+=80',
    end: 'bottom bottom',
    pin: stickyItem,
    pinSpacing: false,
  });
};
